const path = process.argv[2];
if (!path) { console.error('Usage: node advice_translation_keys.js <path>'); process.exit(1); }

let src = readFileSync(path, 'utf8');

for (const [lang, keys] of Object.entries(TRANSLATIONS)) {
  const marker  = `const ${lang} = {\n`;
  const idx     = src.indexOf(marker);
  if (idx === -1) { console.log(`SKIP: ${lang} not found`); continue; }
  const insertAt = idx + marker.length;
  const langEnd  = src.indexOf('\nconst ', idx + 1);
  const block    = src.slice(idx, langEnd);
  let   added    = '';
  for (const [k, v] of Object.entries(keys)) {
    if (block.includes(`  ${k}:`)) continue;
    added += `  ${k}: ${JSON.stringify(v)},\n`;
  }
  if (added) {
    src = src.slice(0, insertAt) + added + src.slice(insertAt);
    console.log(`✓ ${lang}: added ${added.split('\n').filter(Boolean).length} keys`);
  } else {
    console.log(`${lang}: all keys present`);
  }
}

writeFileSync(path, src);
console.log('Done.');